code = """import json

# Load the data properly
civic_file_path = locals()['var_functions.query_db:34']
funding_records = locals()['var_functions.query_db:35']

with open(civic_file_path, 'r') as f:
    civic_docs = json.load(f)

# Extract the main civic document text
civic_text = civic_docs[0].get('text', '')

# Create final results combining all information
results = []

# Process all funding records
for record in funding_records:
    project_name = record['Project_Name']
    funding_source = record['Funding_Source']
    amount = int(record['Amount'])
    
    # Determine status from project name keywords
    status = 'unknown'
    if 'Design' in project_name:
        status = 'design'
    elif 'Project' in project_name and 'FEMA' in project_name:
        # Most FEMA projects are awaiting approval or in design phase
        status = 'design'
    
    # Determine type (FEMA projects are disaster recovery)
    project_type = 'disaster'
    
    results.append({
        'Project_Name': project_name,
        'Funding_Source': funding_source,
        'Amount': amount,
        'Status': status,
        'Type': project_type
    })

# Sort for consistency
results = sorted(results, key=lambda x: x['Project_Name'])

# Print in required format
print('__RESULT__:')
print(json.dumps(results, indent=2))"""

